    }
    for(int j=2;j<=m;j++)
    {
        for(int i=1;i<=n;i++)
        {
            f[i][j][0]=z(f[i][j-1][1],z(f[i][j-1][0],f[i][j-1][2]))+a[i][j];
            if(i>=2) f[i][j][1]=z(f[i-1][j][0],f[i-1][j][1])+a[i][j]; 
        }
        for(int i=n-1;i>=1;i--)
        {
            f[i][j][2]=z(f[i+1][j][0],f[i+1][j][2])+a[i][j];
        }
    }
    cout<<z(f[n][m][0],z(f[n][m][1],f[n][m][2]));
    return 0;
